package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParseReturnsCSVParserInstance() throws Exception {
        Reader mockReader = mock(Reader.class);

        CSVParser mockParser = mock(CSVParser.class);

        // Create a proxy CSVFormat that overrides parse() to return mockParser
        CSVFormat testFormat = new CSVFormatWrapper(csvFormat, mockParser);

        CSVParser parser = testFormat.parse(mockReader);

        assertNotNull(parser);
        assertSame(mockParser, parser);
    }

    @Test
    void testParseThrowsIOException() {
        Reader mockReader = mock(Reader.class);

        CSVFormat testFormat = new CSVFormat() {
            @Override
            public CSVParser parse(Reader in) throws IOException {
                throw new IOException("mock IO exception");
            }
        };

        IOException thrown = assertThrows(IOException.class, () -> {
            testFormat.parse(mockReader);
        });

        assertEquals("mock IO exception", thrown.getMessage());
    }

    /**
     * Wrapper class to override parse() method without subclassing CSVFormat directly,
     * because CSVFormat is final and has private constructors.
     */
    private static class CSVFormatWrapper extends CSVFormat {
        private final CSVFormat delegate;
        private final CSVParser mockParser;

        CSVFormatWrapper(CSVFormat delegate, CSVParser mockParser) {
            this.delegate = delegate;
            this.mockParser = mockParser;
        }

        @Override
        public CSVParser parse(Reader in) throws IOException {
            return mockParser;
        }

        // Delegate all other methods to the original CSVFormat instance

        @Override
        public char getDelimiter() {
            return delegate.getDelimiter();
        }

        @Override
        public Character getQuoteChar() {
            return delegate.getQuoteChar();
        }

        @Override
        public Quote getQuotePolicy() {
            return delegate.getQuotePolicy();
        }

        @Override
        public Character getCommentStart() {
            return delegate.getCommentStart();
        }

        @Override
        public Character getEscape() {
            return delegate.getEscape();
        }

        @Override
        public boolean getIgnoreSurroundingSpaces() {
            return delegate.getIgnoreSurroundingSpaces();
        }

        @Override
        public boolean getIgnoreEmptyLines() {
            return delegate.getIgnoreEmptyLines();
        }

        @Override
        public String getRecordSeparator() {
            return delegate.getRecordSeparator();
        }

        @Override
        public String getNullString() {
            return delegate.getNullString();
        }

        @Override
        public String[] getHeader() {
            return delegate.getHeader();
        }

        @Override
        public boolean getSkipHeaderRecord() {
            return delegate.getSkipHeaderRecord();
        }

        @Override
        public boolean equals(Object obj) {
            return delegate.equals(obj);
        }

        @Override
        public int hashCode() {
            return delegate.hashCode();
        }

        @Override
        public String toString() {
            return delegate.toString();
        }
    }
}
